import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
/**
 * On a logged-out run, openStudioTo emits auth-required/authenticated itself
 * (synchronously, through its emit sink, before it resolves) and the command
 * emits session-ready only after openStudioTo returns. So the stdout order MUST
 * be auth-required -> authenticated -> session-ready. This pins that the command
 * doesn't reorder session-ready ahead of the lifecycle events.
 */
const emitted = [];
vi.mock("../output.js", () => ({
    emitJson: (obj) => {
        emitted.push(obj);
    },
    blockingNote: (until) => `BLOCKING: ${until}`,
    printBlockingNotice: () => { },
}));
vi.mock("../config.js", () => ({
    getConfig: () => ({ serviceUrl: "https://test.invalid", apiKey: null }),
    hasCredentials: () => false,
}));
const mockOpenStudioTo = vi.fn(async (_path, opts) => {
    // The real openStudioTo emits these lifecycle events itself through its
    // sink (default = emitJson). Simulate that: with no explicit sink the
    // wrapper gets the default, which the output.js mock routes into `emitted`.
    const emit = opts.emit ?? ((event) => emitted.push(event));
    emit({
        event: "auth-required",
        sessionId: "sess-1",
        signInUrl: "https://test.invalid/studio/sign-in",
    });
    emit({ event: "authenticated", sessionId: "sess-1" });
    return {
        sessionId: "sess-1",
        serviceUrl: "https://test.invalid",
        apiKey: "key",
        opened: true,
        abort: vi.fn(),
        done: Promise.resolve(),
    };
});
vi.mock("./openStudioTo.js", () => ({
    openStudioTo: (...args) => mockOpenStudioTo(...args),
    handleStudioError: (err) => {
        throw err;
    },
}));
const TEST_RUN_ID = "11111111-1111-4111-8111-111111111111";
let savedArgv;
beforeEach(() => {
    emitted.length = 0;
    savedArgv = process.argv;
    process.argv = ["node", "openExperiments.js", TEST_RUN_ID];
    vi.spyOn(process, "exit").mockImplementation((() => { }));
});
afterEach(() => {
    process.argv = savedArgv;
    vi.restoreAllMocks();
    mockOpenStudioTo.mockClear();
});
describe("runOpenExperiments auth event ordering", () => {
    it("emits auth-required then authenticated before session-ready when logged out", async () => {
        const { runOpenExperiments } = await import("./openExperiments.js");
        await runOpenExperiments({});
        const order = emitted.map((event) => event.event);
        expect(order.slice(0, 3)).toEqual([
            "auth-required",
            "authenticated",
            "session-ready",
        ]);
    });
});
